INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'overview', 'Overview > Full Name: National Institute of Technology Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'overview', 'Overview > Location: Ravangla, Barfung Road, Namchi District, Sikkim 737139.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'overview', 'Overview > Languages spoken: Mostly Hindi. Local people speak Nepali, Bengali, and Hindi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'overview', 'Overview > Climate: Mostly winter weather. Non-stop rain during rainy season. Summer mornings are sunny but afternoon rain is likely.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'transport', 'Transport > Railway: New Jalpaiguri Station is 120 km from NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'transport', 'Transport > Airport: Bagdogra Airport is 130 km from NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'transport', 'Transport > From airport/station: Take SNT bus or share taxi available till 1 PM. Share taxi costs Rs 450, or Rs 800-900 if there is a landslide on the road.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'transport', 'Transport > Separate cab from airport/station to NIT Sikkim costs Rs 4,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'transport', 'Transport > Daily bus available at 1 PM, fare Rs 280.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'restaurants', 'Restaurants > Many restaurants available in the market 2 km away from NIT Sikkim campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Tourist: Namchi (Chardham temple complex).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Tourist: Pelling.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Tourist: Gangtok.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Tourist: North Sikkim — Lachung, Lachen.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Tourist: Nathula Pass.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Tourist: Kalimpong, Darjeeling, Lamhatta, Tinchule, Downhill.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'nearby_places', 'Nearby Places > Shopping: No malls nearby. Zudio, Trends, Reliance etc. are 26 km away.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Boys: BH-1 (Boys Hostel 1), for 2nd year and above.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Boys: BH-2 (Boys Hostel 2), for 2nd year and above.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Boys: 1st year boys hostel is located 1.5 km outside the main campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Boys: MTech students have 2 hostels within campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Boys: PhD students do not have hostel facility.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Boys Summary: BH-1 and BH-2 for senior BTech boys (in campus). 1st year boys hostel 1.5 km outside campus. 2 MTech hostels in campus. No PhD hostels.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Girls: GH-1 (Girls Hostel 1), located in campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Girls: GH-2 (Girls Hostel 2), located in campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Girls: GH-3 (Girls Hostel 3), located in campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Girls Summary: 3 girls hostels (GH-1, GH-2, GH-3), all within campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'hostels', 'Hostels > Faculty/Staff: FS hostel available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Cost: Rs 140 per day at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Structure: 1 boys mess (serves all boys including MTech and PhD) and 1 girls mess (serves all girls). Same menu for everyone.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Timings: Breakfast 7-9 AM (working days), 8-10 AM (weekends). Lunch 12-2 PM. Tea 5:30-6:30 PM. Dinner 8-9:45 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Monday Breakfast: Sattu/Aloo Paratha.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Monday Lunch: Arhar Dal/Rajma.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Monday Dinner: Shahi Paneer/Butter Chicken.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Tuesday Breakfast: Pav Bhaji/Medu Vada.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Tuesday Lunch: Masoor Dal + Mix Veg.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Tuesday Dinner: Chana Dal Tarka + Aloo Matar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Wednesday Breakfast: Gobi/Veg Paratha.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Wednesday Lunch: Chana Dal + Aloo Dam + Palak.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Wednesday Dinner: Egg Curry/Mushroom Curry.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Thursday Breakfast: Uttapam/Poha + Sev.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Thursday Lunch: Masoor Dal + Besan Kadhi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Thursday Dinner: Puri + Aloo/Gobi Dum + Chole.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Friday Breakfast: Bread Butter Jam + Eggs.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Friday Lunch: Arhar Dal + Cabbage Fry + Soyabean.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Friday Dinner: Paneer Chilli/Chicken Chilli OR Biryani (alternate weeks).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Saturday Breakfast: Dosa/Idli.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Saturday Lunch: Khichdi + Chokha + Papad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Saturday Dinner: Fried Rice + Manchurian.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Sunday Breakfast: Chole Bhatura + Fruit.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Sunday Lunch: Matar Paneer/Fish Curry.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Sunday Dinner: Dal Makhani + Gulab Jamun/Jalebi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Portions: Bread 4 pcs, Butter 10g, Jam 20g, Chicken 120-135g, Egg 2 pcs, Fish 120-135g, Paneer 70-80g, Tea 200ml, Pav 4 pcs.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Biryani is served every 2 weeks (alternate Fridays).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'mess', 'Mess > Cuisine: South Indian, North Indian, and Sikkim food all covered in the menu.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Tuition Fee (full): Rs 62,500 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Tuition Fee (2/3rd remission): Rs 20,834 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Tuition Fee (SC/ST/PwD/income below 1 lakh): Rs 0 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Exam Fee: Rs 870 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Registration Fee: Rs 298 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Library Fee: Rs 926 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Lab Fee: Rs 1,157 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Internet Fee: Rs 585 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Sports Fee: Rs 992 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Medical Fee: Rs 353 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Insurance Fee: Rs 585 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Development Fund: Rs 585 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > T&P Fee: Rs 176 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Department Fee: Rs 585 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Grade Card Fee: Rs 231 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Sub-total (full tuition): Rs 70,945 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Sub-total (2/3rd remission): Rs 29,279 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > One-time Fees: Admission Rs 5,000, ID Card Rs 3,000, Welfare Rs 500, Alumni Rs 7,500, Convocation Rs 750, Caution Deposit Rs 7,500. Total one-time: Rs 16,750 (first semester), Rs 8,250 (subsequent semesters).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Hostel Fees: Mess Caution Rs 7,500 (one-time), Hostel Caution Rs 750, Hostel Fee Rs 1,742, Maintenance Rs 297. Total hostel first semester: Rs 10,927.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Bus Fee (optional): Rs 1,743 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fee_structure', 'Fee Structure > Mess charges are separate from hostel and tuition fees.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'wifi', 'WiFi > 10 GB per day per student at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'wifi', 'WiFi > Uninterrupted connectivity in hostel rooms, classrooms, and labs.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'attendance', 'Attendance > 75% attendance is mandatory at NIT Sikkim. Remaining 25% can be covered by medical certificates.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'clubs', 'Clubs > Student Clubs: Anuvrat, Devcans, Nirmaan, Photography Club, The Regnant Club, Yantrikaa.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'clubs', 'Clubs > Cells: E&I Cell (Entrepreneurship & Innovation), Web Dev Cell, T&P Cell (Training & Placement).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fests', 'Fests > Udgam: Cultural fest at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fests', 'Fests > Abhiyantran: Technical fest at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fests', 'Fests > 2 fests held per year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'laundry', 'Laundry > 1-2 washing machines available per hostel at NIT Sikkim. Costs Rs 50 per wash.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'elections', 'Elections > No student elections held at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'sports', 'Sports > Available: Cricket, Football, Volleyball, Badminton, Kho-Kho, Basketball, Chess, Carrom.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'sports', 'Sports > Annual sports event involving entire college including faculty.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'canteen', 'Canteen > On-campus canteen serving snacks and food at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'canteen', 'Canteen > Small canteen located 100 meters outside campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'canteen', 'Canteen > Grocery shop 1 km away. 2 restaurants 2 km away from campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'shops', 'Shops > Market is 2 km away from NIT Sikkim campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fines', 'Fines > Misbehavior: Rs 20,000 fine + deregistered from college for 1 semester. Very strictly enforced.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'fines', 'Fines > Property damage: Rs 20,000 to Rs 50,000 fine. Very strictly enforced.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'gym', 'Gym > Boys only gym at NIT Sikkim. Free for students. Accessible at any time.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'health_centre', 'Health Centre > Open 8 AM to 10 PM at NIT Sikkim.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'health_centre', 'Health Centre > Ambulance available for emergencies.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'health_centre', 'Health Centre > College bears testing expenses. Students need to buy medicines themselves if not available at the health centre.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'language', 'Language > Mostly Hindi spoken at NIT Sikkim. Local people speak Nepali, Bengali, and Hindi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'climate', 'Climate > Mostly winter weather at NIT Sikkim (Ravangla). Non-stop rain during rainy season. Summer mornings sunny but afternoon rain is likely.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'academics', 'Academics > NIT Sikkim offers B.Tech in CSE (Computer Science), ECE (Electronics & Communication), and EE (Electrical Engineering).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'academics', 'Academics > Timetable covers ECE 4th Sem, 6th Sem, 8th Sem; CSE 4th Sem, 6th Sem; EE 4th Sem.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Sikkim', 'academics', 'Academics > Subjects include Signal Processing, Analog Electronics, Microprocessor, Communication Systems, VLSI, Embedded Systems, and more.');
